  Widget _buildAnimatedFeatureIcon({
    required String assetPath,
    required Color fallbackColor,
    required IconData fallbackIcon,
    required BuildContext context,
  }) {
    final size = ResponsiveHelper.screenWidth(context) < 600 ? 60.0 : 70.0;
    
    return AnimatedBuilder(
      animation: _featureAnimationController,
      builder: (context, child) {
        final bounceValue = (sin(_featureAnimationController.value * 2 * 3.14) * 8);
        return Transform.translate(
          offset: Offset(0, bounceValue),
          child: child,
        );
      },
      child: Image.asset(
        assetPath,
        height: size,
        width: size,
        fit: BoxFit.contain,
        errorBuilder: (context, error, stackTrace) {
          return Container(
            height: size,
            width: size,
            decoration: BoxDecoration(
              color: fallbackColor,
              shape: BoxShape.circle,
              boxShadow: [
                BoxShadow(
                  color: Colors.black.withOpacity(0.2),
                  blurRadius: 6,
                  spreadRadius: 1,
                  offset: const Offset(0, 3),
                ),
              ],
            ),
            child: Center(
              child: Icon(
                fallbackIcon,
                size: size * 0.5,
                color: Colors.white,
              ),
            ),
          );
        },
      ),
    );
  }
  
