                  fontSize: 16,
                  fontWeight: FontWeight.bold,
                  color: Colors.red,
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

// ============ EXERCISE SCREEN ============
class ExerciseScreen extends StatefulWidget {
  final String lessonName;
  final String language;
  final int subLessonIndex;

  const ExerciseScreen({
    super.key,
    required this.lessonName,
    required this.language,
    required this.subLessonIndex,
  });

  @override
  State<ExerciseScreen> createState() => _ExerciseScreenState();
}

class _ExerciseScreenState extends State<ExerciseScreen> {
  List<int> _numbers = [];
  List<int?> _answers = [];
  int _score = 0;
  int _currentQuestion = 0;
  final int _totalQuestions = 10;
  bool _showResult = false;

  @override
  void initState() {
    super.initState();
    _initializeExercise();
  }

  void _initializeExercise() {
    final random = Random();
    _numbers = List.generate(_totalQuestions, (index) => random.nextInt(20) + 1);
    _answers = List.filled(_totalQuestions, null);
  }

  void _answerQuestion(int answer) {
    if (!_showResult) {
      setState(() {
        _answers[_currentQuestion] = answer;
        
        if (_currentQuestion < _totalQuestions - 1) {
          _currentQuestion++;
        } else {
          _calculateScore();
          _showResult = true;
          _recordExerciseResults();
        }
      });
    }
  }

  void _calculateScore() {
    int correct = 0;
    for (int i = 0; i < _totalQuestions; i++) {
      if (_answers[i] == _numbers[i] + 1) {
        correct++;
      }
    }
    _score = (correct / _totalQuestions * 100).toInt();
  }

  void _recordExerciseResults() {
    final percentage = _score;
    
    progressManager.recordExerciseScore(
      widget.lessonName,
      widget.language,
      widget.subLessonIndex,
      'Basic Exercise',
      _score,
      _totalQuestions,
      _score,
      percentage.toDouble(),
    );
  }

  void _restartExercise() {
    setState(() {
      _initializeExercise();
      _currentQuestion = 0;
      _score = 0;
      _showResult = false;
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.white,
      appBar: AppBar(
        backgroundColor: Colors.white,
        leading: IconButton(
          icon: const Icon(Icons.arrow_back, color: Colors.black),
          onPressed: () => Navigator.pop(context),
        ),
        title: Text(
          '${widget.lessonName} Exercise',
          style: const TextStyle(
            fontSize: 20,
            fontWeight: FontWeight.bold,
            color: Colors.black,
          ),
        ),
        centerTitle: true,
        elevation: 0,
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(20.0),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Container(
              width: double.infinity,
              padding: const EdgeInsets.all(15),
              decoration: BoxDecoration(
                color: const Color(0xFFA8D5E3),
                borderRadius: BorderRadius.circular(12),
                border: Border.all(color: Colors.black, width: 1),
              ),
              child: Column(
                children: [
                  Icon(Icons.question_answer, size: 40, color: Colors.black),
                  const SizedBox(height: 10),
                  const Text(
                    'What number comes AFTER the given number?',
                    textAlign: TextAlign.center,
                    style: TextStyle(
                      fontSize: 16,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                  const SizedBox(height: 5),
                  Text(
                    'Question ${_currentQuestion + 1}/$_totalQuestions',
                    style: const TextStyle(
                      fontSize: 14,
                    ),
                  ),
                ],
              ),
            ),

            const SizedBox(height: 20),

            if (!_showResult)
              Container(
                width: double.infinity,
                padding: const EdgeInsets.all(30),
                decoration: BoxDecoration(
                  color: Colors.white,
                  borderRadius: BorderRadius.circular(16),
                  border: Border.all(color: Colors.black, width: 2),
                  boxShadow: [
                    BoxShadow(
                      color: const Color.fromRGBO(0, 0, 0, 0.1),
                      blurRadius: 6,
                      offset: const Offset(3, 3),
                    ),
                  ],
                ),
                child: Column(
                  children: [
                    const Text(
                      'What comes AFTER:',
                      style: TextStyle(fontSize: 20),
                    ),
                    const SizedBox(height: 10),
                    Text(
                      '${_numbers[_currentQuestion]}',
                      style: const TextStyle(
                        fontSize: 60,
                        fontWeight: FontWeight.bold,
                        color: Colors.blue,
                      ),
                    ),
                    const SizedBox(height: 30),
                    
                    Row(
                      children: [
                        Expanded(
                          child: _buildNumberButton(_numbers[_currentQuestion] + 1),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _buildNumberButton(_numbers[_currentQuestion] + 2),
                        ),
                      ],
                    ),
                    const SizedBox(height: 10),
                    Row(
                      children: [
                        Expanded(
                          child: _buildNumberButton(_numbers[_currentQuestion] + 3),
                        ),
                        const SizedBox(width: 10),
                        Expanded(
                          child: _buildNumberButton(_numbers[_currentQuestion] + 4),
                        ),
                      ],
                    ),
                  ],
                ),
              ),

            if (_showResult)
              Container(
                width: double.infinity,
                padding: const EdgeInsets.all(30),
                decoration: BoxDecoration(
                  color: _score >= 70 ? Colors.green[100] : Colors.orange[100],
                  borderRadius: BorderRadius.circular(16),
                  border: Border.all(
                    color: _score >= 70 ? Colors.green : Colors.orange,
                    width: 2,
                  ),
                ),
                child: Column(
                  children: [
                    Icon(
                      _score >= 70 ? Icons.celebration : Icons.emoji_objects,
                      size: 50,
                      color: _score >= 70 ? Colors.green : Colors.orange,
                    ),
                    const SizedBox(height: 10),
                    Text(
                      _score >= 70 
                          ? 'Great Job! You scored $_score%' 
                          : 'You scored $_score%. Keep practicing!',
                      textAlign: TextAlign.center,
                      style: const TextStyle(
                        fontSize: 18,
                        fontWeight: FontWeight.bold,
                      ),
                    ),
                    const SizedBox(height: 20),
                    ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: const Color(0xFFFFF59D),
                        foregroundColor: Colors.black,
                      ),
                      onPressed: _restartExercise,
                      child: const Text(
                        'Try Again',
                        style: TextStyle(fontWeight: FontWeight.bold),
                      ),
                    ),
                  ],
                ),
              ),

            const SizedBox(height: 30),

            if (!_showResult)
              Row(
                children: [
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: Colors.white,
                        foregroundColor: Colors.black,
                        minimumSize: const Size(0, 50),
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(25),
                          side: const BorderSide(color: Colors.black, width: 1),
                        ),
                      ),
                      onPressed: _currentQuestion > 0 ? () {
                        setState(() {
                          _currentQuestion--;
                        });
                      } : null,
                      child: const Icon(Icons.arrow_back),
                    ),
                  ),
                  const SizedBox(width: 10),
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: const Color(0xFFFFF59D),
                        foregroundColor: Colors.black,
                        minimumSize: const Size(0, 50),
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(25),
                          side: const BorderSide(color: Colors.black, width: 1),
                        ),
                      ),
                      onPressed: () {
                        if (_currentQuestion < _totalQuestions - 1) {
                          setState(() {
                            _currentQuestion++;
                          });
                        } else {
                          _calculateScore();
                          setState(() {
                            _showResult = true;
                          });
                          _recordExerciseResults();
                        }
                      },
                      child: Text(
                        _currentQuestion == _totalQuestions - 1 ? 'Finish' : 'Next',
                        style: const TextStyle(
                          fontSize: 16,
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                    ),
                  ),
                ],
              ),
          ],
        ),
      ),
    );
  }

  Widget _buildNumberButton(int number) {
    return ElevatedButton(
      style: ElevatedButton.styleFrom(
        backgroundColor: Colors.white,
        foregroundColor: Colors.black,
        minimumSize: const Size(0, 60),
        shape: RoundedRectangleBorder(
          borderRadius: BorderRadius.circular(12),
          side: const BorderSide(color: Colors.black, width: 1),
        ),
      ),
      onPressed: () => _answerQuestion(number),
      child: Text(
        '$number',
        style: const TextStyle(
          fontSize: 24,
          fontWeight: FontWeight.bold,
        ),
      ),
    );
  }
}

