// ============ CREATE ACCOUNT SCREEN ============
class CreateAccountScreen extends StatefulWidget {
  const CreateAccountScreen({super.key});

  @override
  State<CreateAccountScreen> createState() => _CreateAccountScreenState();
}

class _CreateAccountScreenState extends State<CreateAccountScreen> {
  final TextEditingController _firstNameController = TextEditingController();
  final TextEditingController _lastNameController = TextEditingController();
  final TextEditingController _emailController = TextEditingController();
  final TextEditingController _passwordController = TextEditingController();
  final TextEditingController _confirmPasswordController = TextEditingController();
  final LocalAuthService _authService = LocalAuthService();

  bool _isPasswordVisible = false;
  bool _isConfirmPasswordVisible = false;
  bool _isLoading = false;
  
  // List of schools
  final List<String> _schools = [
    'San Miguel National HighSchool',
    'Bajet-Castillo High School',
    'Pulong Buhangin National High School'
  ];
  
  // List of sections (Grade 7-10)
  final List<String> _sections = [
    'Grade 7',
    'Grade 8',
    'Grade 9',
    'Grade 10',
    'Non-graded',
  ];
  
  String? _selectedSchool;
  String? _selectedSection;

  Future<void> _createAccount() async {
    final firstName = _firstNameController.text.trim();
    final lastName = _lastNameController.text.trim();
    final email = _emailController.text.trim();
    final password = _passwordController.text;
    final confirmPassword = _confirmPasswordController.text;
    final school = _selectedSchool;
    final section = _selectedSection;

    // Validation for all fields
    if (firstName.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please enter your first name',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (lastName.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please enter your last name',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (email.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please enter your email',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    // Validation para siguraduhing may @gmail.com ang email
    if (!email.endsWith('@gmail.com')) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please use a valid Gmail address (@gmail.com)',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (password.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please enter a password',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (password.length < 6) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Password must be at least 6 characters',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (password != confirmPassword) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Passwords do not match',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (school == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please select your school',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (section == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please select your Grade Level',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    // Show loading
    setState(() {
      _isLoading = true;
    });

    try {
      // Register user in database
      final fullName = '$firstName $lastName';
      
      // Try backend API first
      try {
        final apiResult = await ApiService.register(
          email: email,
          password: password,
          name: fullName,
          school: school,
          section: section,
        );

        if (apiResult['success']) {
          // Save token
          ApiService.setToken(apiResult['data']['token']);
          
          // Also save to local storage as backup
          await _authService.registerWithEmail(
            email: email,
            password: password,
            name: fullName,
            school: school,
            section: section,
          );

          if (mounted) {
            // Save user data in provider
            UserProvider.setUser(UserData(
              name: fullName,
              email: email,
              school: school,
              section: section,
            ));

            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
                content: Text(
                  'Account created successfully! (Synced to server)',
                  style: TextStyle(fontFamily: 'Poppins-Regular', fontWeight: FontWeight.bold),
                ),
                backgroundColor: Colors.green,
                duration: const Duration(seconds: 2),
              ),
            );

            Future.delayed(const Duration(milliseconds: 1500), () {
              if (mounted) {
                Navigator.pushReplacement(
                  context,
                  MaterialPageRoute(builder: (context) => const DashboardScreen()),
                );
              }
            });
          }
          return;
        }
      } catch (apiError) {
        print('Backend API unavailable, using local storage: $apiError');
      }

      // Fallback to local storage only
      final user = await _authService.registerWithEmail(
        email: email,
        password: password,
        name: fullName,
        school: school,
        section: section,
      );

      if (user != null) {
        // Save user data in provider
        UserProvider.setUser(UserData(
          name: fullName,
          email: email,
          school: school,
          section: section,
        ));

        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text(
                'Account created successfully! (Local only)',
                style: TextStyle(fontFamily: 'Poppins-Regular', fontWeight: FontWeight.bold),
              ),
              backgroundColor: Colors.orange,
              duration: const Duration(seconds: 2),
            ),
          );

          Future.delayed(const Duration(milliseconds: 1500), () {
            if (mounted) {
              Navigator.pushReplacement(
                context,
                MaterialPageRoute(builder: (context) => const DashboardScreen()),
              );
            }
          });
        }
      }
    } catch (e) {
      if (mounted) {
        setState(() {
          _isLoading = false;
        });

        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text(
              e.toString().replaceAll('Exception: ', ''),
              style: TextStyle(fontFamily: 'Poppins-Regular'),
            ),
            backgroundColor: Colors.red,
            duration: const Duration(seconds: 3),
          ),
        );
      }
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: Colors.white, // White background
      body: SafeArea(
        child: Stack(
          children: [
            // Background decorative elements
            Positioned(
              top: -50,
              right: -50,
