                icon: const Icon(Icons.arrow_drop_down, color: Colors.black),
                iconSize: 30,
                isExpanded: true,
                style: TextStyle(
                  fontFamily: 'Poppins-Regular',
                  fontSize: 16,
                  color: Colors.black,
                ),
                items: items,
                onChanged: onChanged,
              ),
            ),
          ),
        ),
      ],
    );
  }

  Widget _buildPasswordField({
    required TextEditingController controller,
    required String label,
    required String hintText,
    required bool isPasswordVisible,
    required VoidCallback onToggleVisibility,
  }) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          label,
          style: TextStyle(
            fontSize: 16,
            fontWeight: FontWeight.bold,
            fontFamily: 'Lora-Regular',
            color: Colors.black,
          ),
        ),
        const SizedBox(height: 8),
        Container(
          decoration: BoxDecoration(
            color: const Color(0xFFF8F8F8),
            borderRadius: BorderRadius.circular(10),
            border: Border.all(
              color: Colors.black,
              width: 1,
            ),
            boxShadow: [
              BoxShadow(
                color: Colors.black.withOpacity(0.05),
                blurRadius: 5,
                offset: const Offset(0, 2),
              ),
            ],
          ),
          child: TextField(
            controller: controller,
            obscureText: !isPasswordVisible,
            decoration: InputDecoration(
              contentPadding: const EdgeInsets.symmetric(horizontal: 15, vertical: 18),
              hintText: hintText,
              hintStyle: TextStyle(
                fontFamily: 'Poppins-Regular',
                color: Colors.grey[600],
              ),
              border: InputBorder.none,
              prefixIcon: const Icon(Icons.lock, color: Colors.black),
              suffixIcon: IconButton(
                icon: Icon(
                  isPasswordVisible ? Icons.visibility : Icons.visibility_off,
                  color: Colors.black,
                ),
                onPressed: onToggleVisibility,
              ),
              filled: true,
              fillColor: Colors.transparent,
            ),
            style: TextStyle(
              fontFamily: 'Poppins-Regular',
              fontSize: 16,
              color: Colors.black,
            ),
          ),
        ),
      ],
    );
  }
}

// ============ LOG IN SCREEN (WITHOUT PICTURE) ============
class LogInScreen extends StatefulWidget {
  const LogInScreen({super.key});

  @override
  State<LogInScreen> createState() => _LogInScreenState();
}

class _LogInScreenState extends State<LogInScreen> {
  // ADD THESE CONTROLLERS
  final TextEditingController _emailController = TextEditingController();
  final TextEditingController _passwordController = TextEditingController();
  final LocalAuthService _authService = LocalAuthService();

  bool _isPasswordVisible = false;
  bool _isLoading = false;

  Future<void> _logIn() async {
    final email = _emailController.text.trim();
    final password = _passwordController.text;

    if (email.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please enter your email',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    // DAGDAG: Validation para siguraduhing may @gmail.com ang email
    if (!email.endsWith('@gmail.com')) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please use a valid Gmail address (@gmail.com)',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    if (password.isEmpty) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Please enter your password',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.red,
        ),
      );
      return;
    }

    // Show loading
    setState(() {
      _isLoading = true;
    });

    try {
      // Try backend API first
      try {
        final apiResult = await ApiService.login(
          email: email,
          password: password,
        );

        if (apiResult['success']) {
          // Save token
          ApiService.setToken(apiResult['data']['token']);
          final userData = apiResult['data']['user'];
          
          // Also authenticate locally as backup
          await _authService.signInWithEmail(
            email: email,
            password: password,
          );

          // Load progress from backend
          try {
            final progressResult = await ApiService.getProgress();
            if (progressResult['success']) {
              // TODO: Merge backend progress with local
              print('Loaded ${progressResult['data']['progress'].length} progress items from server');
            }
          } catch (e) {
            print('Could not load progress from server: $e');
          }

          if (mounted) {
            // Set user in provider
            UserProvider.setUser(UserData(
              name: userData['name'],
              email: userData['email'],
              school: userData['school'],
              section: userData['section'],
            ));

            ScaffoldMessenger.of(context).showSnackBar(
              SnackBar(
                content: Text(
                  'Logged in successfully! (Synced with server)',
                  style: TextStyle(fontFamily: 'Poppins-Regular', fontWeight: FontWeight.bold),
                ),
                backgroundColor: Colors.green,
                duration: const Duration(seconds: 2),
              ),
            );

            Future.delayed(const Duration(milliseconds: 1500), () {
              if (mounted) {
                Navigator.pushReplacement(
                  context,
                  MaterialPageRoute(builder: (context) => const DashboardScreen()),
                );
              }
            });
          }
          return;
        }
      } catch (apiError) {
        print('Backend API unavailable, using local storage: $apiError');
      }

      // Fallback to local authentication
      final user = await _authService.signInWithEmail(
        email: email,
        password: password,
      );

      if (user != null) {
        // Set user in provider
        UserProvider.setUser(UserData(
          name: user.name,
          email: user.email,
          school: user.school,
          section: user.section,
        ));

        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(
              content: Text(
                'Logged in successfully! (Local only)',
                style: TextStyle(fontFamily: 'Poppins-Regular', fontWeight: FontWeight.bold),
              ),
              backgroundColor: Colors.orange,
              duration: const Duration(seconds: 2),
            ),
          );

          Future.delayed(const Duration(milliseconds: 1500), () {
            if (mounted) {
              Navigator.pushReplacement(
                context,
                MaterialPageRoute(builder: (context) => const DashboardScreen()),
              );
            }
          });
        }
      }
    } catch (e) {
      if (mounted) {
        setState(() {
          _isLoading = false;
        });

        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(
            content: Text(
              e.toString().replaceAll('Exception: ', ''),
              style: TextStyle(fontFamily: 'Poppins-Regular'),
            ),
            backgroundColor: Colors.red,
            duration: const Duration(seconds: 3),
          ),
        );
      }
    }
  }

