            if (_hasUserInput && _isAvatarLoading)
              Positioned.fill(
                child: Container(
                  color: Colors.white,
                  child: const Center(
                    child: CircularProgressIndicator(
                      color: Colors.yellow,
                    ),
                  ),
                ),
              ),
            
            // TRANSLATING OVERLAY
            if (_isTranslating)
              Positioned.fill(
                child: Container(
                  decoration: BoxDecoration(
                    color: const Color(0xFFA8D5E3),
                    border: Border.all(color: Colors.black, width: 2),
                  ),
                  child: const Center(
                    child: Column(
                      mainAxisAlignment: MainAxisAlignment.center,
                      children: [
                        CircularProgressIndicator(
                          color: Colors.yellow,
                        ),
                        SizedBox(height: 16),
                        Text(
                          'Translating...',
                          style: TextStyle(
                            fontFamily: 'Poppins-Regular',
                            fontSize: 16,
                            fontWeight: FontWeight.bold,
                            color: Colors.white,
                          ),
                        ),
                      ],
                    ),
                  ),
                ),
              ),
            
            // ERROR OVERLAY
            if (_hasUserInput && _hasAvatarError && !_isAvatarLoading)
              Positioned.fill(
                child: Container(
                  color: Colors.white,
                  child: const Center(
                    child: Icon(
                      Icons.error_outline,
                      size: 60,
                      color: Colors.red,
                    ),
                  ),
                ),
              ),
          ],
        ),
      ),
    );
  }

  Widget _buildFallbackAvatar() {
    return Container(
      width: 500,
      height: 500,
      decoration: BoxDecoration(
        color: const Color(0xFFA8D5E3),
        border: Border.all(color: Colors.black, width: 2),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.1),
            blurRadius: 8,
            offset: const Offset(0, 4),
          ),
        ],
      ),
      child: const Center(
        child: Icon(
          Icons.person,
          size: 150,
          color: Colors.white,
        ),
      ),
    );
  }
}

