    TextEditingController controller = TextEditingController();
    
    return Column(
      children: [
        Container(
          padding: const EdgeInsets.symmetric(vertical: 16, horizontal: 20),
          decoration: BoxDecoration(
            color: Colors.green[50],
            borderRadius: BorderRadius.circular(12),
            border: Border.all(color: Colors.green, width: 1.5),
          ),
          child: Text(
            question['question'] as String,
            style: const TextStyle(fontSize: 20, fontWeight: FontWeight.w600),
            textAlign: TextAlign.center,
          ),
        ),
        
        const SizedBox(height: 20),
        
        if (!_answeredQuestions[_currentQuestion])
          Container(
            width: screenWidth * 0.4,
            child: TextField(
              controller: controller,
              textAlign: TextAlign.center,
              keyboardType: TextInputType.number,
              decoration: InputDecoration(
                hintText: 'Enter number',
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(10),
                  borderSide: BorderSide(color: Colors.green, width: 2),
                ),
                focusedBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(10),
                  borderSide: BorderSide(color: Colors.green, width: 2),
                ),
                filled: true,
                fillColor: Colors.white,
              ),
              style: const TextStyle(fontSize: 20, fontWeight: FontWeight.bold),
            ),
          )
        else if (_userAnswers[_currentQuestion] != null)
          Container(
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: Colors.blue, width: 2),
            ),
            child: Text(
              'Your answer: ${_userAnswers[_currentQuestion]}',
              style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
            ),
          ),
        
        const SizedBox(height: 16),
        
        if (!_answeredQuestions[_currentQuestion])
          ElevatedButton(
            style: ElevatedButton.styleFrom(
              backgroundColor: Colors.green,
              foregroundColor: Colors.white,
              minimumSize: const Size(120, 40),
            ),
            onPressed: () {
              if (controller.text.isNotEmpty) {
                _answerQuestion(controller.text);
              }
            },
            child: const Text('Submit', style: TextStyle(fontSize: 16)),
          ),
      ],
    );
  }

  // ===== MATCHING TYPE BUILDER =====
  Widget _buildMatching(Map<String, dynamic> question, double screenWidth) {
    final leftItems = question['leftItems'] as List;
    final rightItems = question['rightItems'] as List;
    Map<int, int> localMatches = {};

    return Container(
      padding: const EdgeInsets.all(12),
      decoration: BoxDecoration(
        color: Colors.purple[50],
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: Colors.purple, width: 1.5),
      ),
      child: Column(
        children: [
          // Headers
          Row(
            children: [
              Expanded(
                child: Container(
                  padding: const EdgeInsets.all(8),
                  decoration: BoxDecoration(
                    color: Colors.purple[100],
                    borderRadius: BorderRadius.circular(6),
                  ),
                  child: const Text(
                    'Item',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 14),
                    textAlign: TextAlign.center,
                  ),
                ),
              ),
              const SizedBox(width: 10),
              Expanded(
                child: Container(
                  padding: const EdgeInsets.all(8),
                  decoration: BoxDecoration(
                    color: Colors.purple[100],
                    borderRadius: BorderRadius.circular(6),
                  ),
                  child: const Text(
                    'Match',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 14),
                    textAlign: TextAlign.center,
                  ),
                ),
              ),
            ],
          ),
          
          const SizedBox(height: 12),
          
          // Matching rows
          ...List.generate(leftItems.length, (index) {
            return Padding(
              padding: const EdgeInsets.only(bottom: 10),
              child: Row(
                children: [
                  // Left item
                  Expanded(
                    child: Container(
                      padding: const EdgeInsets.all(12),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.grey[300]!),
                      ),
                      child: Text(
                        leftItems[index] as String,
                        textAlign: TextAlign.center,
                        style: const TextStyle(fontSize: 13),
                      ),
                    ),
                  ),
                  
                  const SizedBox(width: 10),
                  
                  // Right dropdown
                  Expanded(
                    child: Container(
                      padding: const EdgeInsets.symmetric(horizontal: 8),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.purple[300]!),
                      ),
                      child: DropdownButton<int>(
                        value: localMatches[index],
                        hint: const Text('Select', style: TextStyle(fontSize: 13)),
                        isExpanded: true,
                        underline: const SizedBox(),
                        iconSize: 22,
                        items: List.generate(rightItems.length, (i) {
                          return DropdownMenuItem<int>(
                            value: i,
                            child: Text(rightItems[i] as String, style: const TextStyle(fontSize: 13)),
                          );
                        }),
                        onChanged: _answeredQuestions[_currentQuestion] 
                            ? null 
                            : (value) {
                                setState(() {
                                  localMatches[index] = value!;
                                  if (localMatches.length == leftItems.length) {
                                    _answerQuestion(localMatches);
                                  }
                                });
                              },
                      ),
                    ),
                  ),
                ],
              ),
            );
          }),
        ],
      ),
    );
  }

  // ===== DRAG AND DROP BUILDER =====
  Widget _buildDragDrop(Map<String, dynamic> question, double screenWidth) {
    final sequence = question['sequence'] as List;
    final blankPositions = question['blankPositions'] as List;
    
    return StatefulBuilder(
      builder: (context, setState) {
        return Column(
          children: [
            // Sequence with blanks
            Container(
              padding: const EdgeInsets.all(16),
              decoration: BoxDecoration(
                color: Colors.orange[50],
                borderRadius: BorderRadius.circular(12),
                border: Border.all(color: Colors.orange, width: 1.5),
              ),
              child: Column(
                children: [
                  const Text(
                    'Complete the sequence:',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 14),
                  ),
                  const SizedBox(height: 12),
                  Wrap(
                    alignment: WrapAlignment.center,
                    spacing: 8,
                    runSpacing: 8,
                    children: List.generate(sequence.length, (index) {
                      if (blankPositions.contains(index)) {
                        final filledIndex = blankPositions.indexOf(index);
                        final filledValue = _dragTargets[filledIndex];
                        return Container(
                          width: 50,
                          height: 50,
                          decoration: BoxDecoration(
                            color: filledValue.isEmpty ? Colors.orange[100] : Colors.white,
                            borderRadius: BorderRadius.circular(8),
                            border: Border.all(
                              color: filledValue.isEmpty ? Colors.orange : Colors.orange[700]!,
                              width: 2,
                            ),
                          ),
                          child: DragTarget<String>(
                            builder: (context, candidateData, rejectedData) {
                              return Center(
                                child: Text(
                                  filledValue,
                                  style: const TextStyle(
                                    fontSize: 16,
                                    fontWeight: FontWeight.bold,
                                  ),
                                ),
                              );
                            },
                            onWillAccept: (data) {
                              return filledValue.isEmpty;
                            },
                            onAccept: (data) {
                              setState(() {
                                _dragTargets[filledIndex] = data;
                                _dragItems.remove(data);
                              });
                            },
                          ),
                        );
                      } else {
                        return Container(
                          width: 50,
                          height: 50,
                          decoration: BoxDecoration(
                            color: Colors.white,
                            borderRadius: BorderRadius.circular(8),
                            border: Border.all(color: Colors.orange, width: 2),
                          ),
                          child: Center(
                            child: Text(
                              sequence[index] as String,
                              style: const TextStyle(
                                fontSize: 16,
                                fontWeight: FontWeight.bold,
                              ),
                            ),
                          ),
                        );
                      }
                    }),
                  ),
                ],
              ),
            ),
            
            const SizedBox(height: 16),
            
            // Drag items
            Container(
              padding: const EdgeInsets.all(16),
              decoration: BoxDecoration(
                color: Colors.teal[50],
                borderRadius: BorderRadius.circular(12),
                border: Border.all(color: Colors.teal, width: 1.5),
              ),
              child: Column(
                children: [
                  const Text(
                    'Drag numbers:',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 14),
                  ),
                  const SizedBox(height: 12),
                  Wrap(
                    spacing: 8,
                    runSpacing: 8,
                    children: _dragItems.map((item) {
                      return Draggable<String>(
                        data: item,
                        feedback: Material(
                          child: Container(
                            padding: const EdgeInsets.all(12),
                            decoration: BoxDecoration(
                              color: Colors.teal,
                              borderRadius: BorderRadius.circular(8),
                              boxShadow: [
                                BoxShadow(
                                  color: Colors.black.withOpacity(0.2),
                                  blurRadius: 4,
                                  offset: const Offset(0, 2),
                                ),
                              ],
                            ),
                            child: Text(
                              item,
                              style: const TextStyle(
                                color: Colors.white,
                                fontSize: 16,
                                fontWeight: FontWeight.bold,
                              ),
                            ),
                          ),
                        ),
                        childWhenDragging: Container(
                          padding: const EdgeInsets.all(12),
                          decoration: BoxDecoration(
                            color: Colors.grey[300],
                            borderRadius: BorderRadius.circular(8),
                          ),
                          child: Text(
                            item,
                            style: const TextStyle(
                              color: Colors.grey,
                              fontSize: 16,
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                        ),
                        child: Container(
                          padding: const EdgeInsets.all(12),
                          decoration: BoxDecoration(
                            color: Colors.white,
                            borderRadius: BorderRadius.circular(8),
                            border: Border.all(color: Colors.teal, width: 2),
                          ),
                          child: Text(
                            item,
                            style: const TextStyle(
                              fontSize: 16,
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                        ),
                      );
                    }).toList(),
                  ),
                ],
              ),
            ),
            
            const SizedBox(height: 16),
            
            if (!_dragTargets.contains('') && !_answeredQuestions[_currentQuestion])
              ElevatedButton(
                style: ElevatedButton.styleFrom(
                  backgroundColor: Colors.green,
                  foregroundColor: Colors.white,
                  minimumSize: const Size(160, 44),
                ),
                onPressed: () {
                  final List<String> answer = [];
                  for (int i = 0; i < blankPositions.length; i++) {
                    answer.add(_dragTargets[i]);
                  }
                  _answerQuestion(answer);
                },
                child: const Text('Submit Answer', style: TextStyle(fontSize: 16)),
              ),
          ],
        );
      },
    );
  }

  // ===== TRUE/FALSE BUILDER =====
  Widget _buildTrueFalse(Map<String, dynamic> question, double screenWidth) {
    return Column(
      children: [
        Container(
          padding: const EdgeInsets.all(16),
          decoration: BoxDecoration(
            color: Colors.red[50],
            borderRadius: BorderRadius.circular(12),
            border: Border.all(color: Colors.red, width: 1.5),
          ),
          child: Text(
            question['question'] as String,
            style: const TextStyle(fontSize: 18),
            textAlign: TextAlign.center,
          ),
        ),
        
        const SizedBox(height: 20),
        
        Row(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            // True button
            GestureDetector(
              onTap: _answeredQuestions[_currentQuestion] ? null : () => _answerQuestion(true),
              child: Container(
                width: 100,
                height: 60,
                margin: const EdgeInsets.symmetric(horizontal: 10),
                decoration: BoxDecoration(
                  color: _answeredQuestions[_currentQuestion] && _userAnswers[_currentQuestion] == true
                      ? (_isAnswerCorrect(question) ? Colors.green : Colors.red)
                      : Colors.white,
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(
                    color: _answeredQuestions[_currentQuestion] && _userAnswers[_currentQuestion] == true
                        ? (_isAnswerCorrect(question) ? Colors.green : Colors.red)
                        : Colors.green,
                    width: 2,
                  ),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.1),
                      blurRadius: 4,
                      offset: const Offset(0, 2),
                    ),
                  ],
                ),
                child: Center(
                  child: Text(
                    'TRUE',
                    style: TextStyle(
                      fontSize: 18,
                      fontWeight: FontWeight.bold,
                      color: _answeredQuestions[_currentQuestion] && _userAnswers[_currentQuestion] == true
                          ? Colors.white
                          : Colors.green,
                    ),
                  ),
                ),
              ),
            ),
            
            // False button
            GestureDetector(
              onTap: _answeredQuestions[_currentQuestion] ? null : () => _answerQuestion(false),
              child: Container(
                width: 100,
                height: 60,
                margin: const EdgeInsets.symmetric(horizontal: 10),
                decoration: BoxDecoration(
                  color: _answeredQuestions[_currentQuestion] && _userAnswers[_currentQuestion] == false
                      ? (_isAnswerCorrect(question) ? Colors.green : Colors.red)
                      : Colors.white,
                  borderRadius: BorderRadius.circular(10),
                  border: Border.all(
                    color: _answeredQuestions[_currentQuestion] && _userAnswers[_currentQuestion] == false
                        ? (_isAnswerCorrect(question) ? Colors.green : Colors.red)
                        : Colors.red,
                    width: 2,
                  ),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.1),
                      blurRadius: 4,
                      offset: const Offset(0, 2),
                    ),
                  ],
                ),
                child: Center(
                  child: Text(
                    'FALSE',
                    style: TextStyle(
                      fontSize: 18,
                      fontWeight: FontWeight.bold,
                      color: _answeredQuestions[_currentQuestion] && _userAnswers[_currentQuestion] == false
                          ? Colors.white
                          : Colors.red,
                    ),
                  ),
                ),
              ),
            ),
          ],
        ),
      ],
    );
  }

  // ===== CIRCLE THE ANSWER BUILDER =====
  Widget _buildCircleAnswer(Map<String, dynamic> question, double screenWidth) {
    return Column(
      children: [
        Container(
          padding: const EdgeInsets.all(16),
          decoration: BoxDecoration(
            color: Colors.teal[50],
            borderRadius: BorderRadius.circular(12),
            border: Border.all(color: Colors.teal, width: 1.5),
          ),
          child: Text(
            question['question'] as String,
            style: const TextStyle(fontSize: 18, fontWeight: FontWeight.w500),
            textAlign: TextAlign.center,
          ),
        ),
        
        const SizedBox(height: 20),
        
        GridView.builder(
          shrinkWrap: true,
          physics: const NeverScrollableScrollPhysics(),
          gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
            crossAxisCount: 2,
            childAspectRatio: screenWidth > 600 ? 2.5 : 2.2,
            crossAxisSpacing: 12,
            mainAxisSpacing: 12,
          ),
          itemCount: (question['options'] as List).length,
          itemBuilder: (context, index) {
            final isAnswered = _answeredQuestions[_currentQuestion];
            final isSelected = _userAnswers[_currentQuestion] == index;
            final isCorrect = index == (question['correctAnswer'] as int);

            Color buttonColor = Colors.white;
            if (isAnswered) {
              if (isSelected && isCorrect) {
                buttonColor = Colors.green;
              } else if (isSelected && !isCorrect) {
                buttonColor = Colors.red;
              } else if (isCorrect) {
                buttonColor = Colors.green[100]!;
              }
            }

            return GestureDetector(
              onTap: isAnswered ? null : () => _answerQuestion(index),
              child: Container(
                decoration: BoxDecoration(
                  color: buttonColor,
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(
                    color: isSelected ? Colors.black : Colors.teal,
                    width: isSelected ? 3 : 2,
                  ),
                  boxShadow: [
                    BoxShadow(
                      color: Colors.black.withOpacity(0.1),
                      blurRadius: 4,
                      offset: const Offset(0, 2),
                    ),
                  ],
                ),
                child: Center(
                  child: Text(
                    (question['options'] as List)[index] as String,
                    style: TextStyle(
                      fontSize: screenWidth > 600 ? 18 : 16,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                ),
              ),
            );
          },
        ),
      ],
    );
  }

  // ===== WRITE THE NUMBER BUILDER =====
  Widget _buildWriteNumber(Map<String, dynamic> question, double screenWidth) {
    TextEditingController controller = TextEditingController();
    
    return Column(
      children: [
        Container(
          padding: const EdgeInsets.all(16),
          decoration: BoxDecoration(
            color: Colors.amber[50],
            borderRadius: BorderRadius.circular(12),
            border: Border.all(color: Colors.amber, width: 1.5),
          ),
          child: Text(
            question['question'] as String,
            style: const TextStyle(fontSize: 18),
            textAlign: TextAlign.center,
          ),
        ),
        
        const SizedBox(height: 20),
        
        if (!_answeredQuestions[_currentQuestion])
          Container(
            width: screenWidth * 0.5,
            child: TextField(
              controller: controller,
              textAlign: TextAlign.center,
              keyboardType: TextInputType.number,
              decoration: InputDecoration(
                hintText: 'Type number',
                border: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(10),
                  borderSide: BorderSide(color: Colors.amber, width: 2),
                ),
                focusedBorder: OutlineInputBorder(
                  borderRadius: BorderRadius.circular(10),
                  borderSide: BorderSide(color: Colors.amber, width: 2),
                ),
                filled: true,
                fillColor: Colors.white,
              ),
              style: const TextStyle(fontSize: 22, fontWeight: FontWeight.bold),
            ),
          )
        else if (_userAnswers[_currentQuestion] != null)
          Container(
            padding: const EdgeInsets.all(12),
            decoration: BoxDecoration(
              color: Colors.white,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: Colors.blue, width: 2),
            ),
            child: Text(
              'Your answer: ${_userAnswers[_currentQuestion]}',
              style: const TextStyle(fontSize: 18, fontWeight: FontWeight.bold),
            ),
          ),
        
        const SizedBox(height: 16),
        
        if (!_answeredQuestions[_currentQuestion])
          ElevatedButton(
            style: ElevatedButton.styleFrom(
              backgroundColor: Colors.amber,
              foregroundColor: Colors.black,
              minimumSize: const Size(120, 44),
            ),
            onPressed: () {
              if (controller.text.isNotEmpty) {
                _answerQuestion(controller.text);
              }
            },
            child: const Text('Submit', style: TextStyle(fontSize: 16, fontWeight: FontWeight.bold)),
          ),
      ],
    );
  }

  // ===== RESULTS SCREEN =====
  Widget _buildResultsScreen() {
    final percentage = (_score / _questions.length * 100).round();
    final screenWidth = MediaQuery.of(context).size.width;

    String message;
    String emoji;
    Color color;

    if (percentage == 100) {
      message = 'Perfect Score!';
      emoji = '🏆';
      color = Colors.amber;
    } else if (percentage >= 80) {
      message = 'Great Job!';
      emoji = '🎉';
      color = Colors.green;
    } else if (percentage >= 60) {
      message = 'Good Try!';
      emoji = '👍';
      color = Colors.blue;
    } else {
      message = 'Keep Practicing!';
      emoji = '💪';
      color = Colors.orange;
    }

    return Scaffold(
      backgroundColor: Colors.white,
      appBar: AppBar(
        backgroundColor: Colors.white,
        leading: IconButton(
          icon: const Icon(Icons.arrow_back, color: Colors.black),
          onPressed: () => Navigator.pop(context),
        ),
        title: const Text('Exercise Complete'),
        centerTitle: true,
        elevation: 0,
      ),
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(20),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Text(
                emoji,
                style: const TextStyle(fontSize: 80),
              ),
              const SizedBox(height: 20),
              Text(
                message,
                style: TextStyle(
                  fontSize: screenWidth > 600 ? 32 : 28,
                  fontWeight: FontWeight.bold,
                  color: color,
                ),
              ),
              const SizedBox(height: 30),
              Container(
                padding: const EdgeInsets.all(24),
                decoration: BoxDecoration(
                  color: color.withOpacity(0.1),
                  borderRadius: BorderRadius.circular(20),
                  border: Border.all(color: color, width: 3),
                  boxShadow: [
                    BoxShadow(
                      color: color.withOpacity(0.3),
                      blurRadius: 12,
                      offset: const Offset(0, 6),
                    ),
                  ],
                ),
                child: Column(
                  children: [
                    const Text(
                      'Your Score',
                      style: TextStyle(fontSize: 18),
                    ),
                    const SizedBox(height: 10),
                    Text(
                      '$_score/${_questions.length}',
                      style: const TextStyle(fontSize: 48, fontWeight: FontWeight.bold),
                    ),
                    const SizedBox(height: 6),
                    Text(
                      '$percentage%',
                      style: const TextStyle(fontSize: 28),
                    ),
                  ],
                ),
              ),
              const SizedBox(height: 40),
              Row(
                children: [
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: Colors.white,
                        foregroundColor: Colors.black,
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(30),
                          side: const BorderSide(color: Colors.black, width: 1.5),
                        ),
                        padding: const EdgeInsets.symmetric(vertical: 16),
                      ),
                      onPressed: _restartExercise,
                      child: const Text('Try Again', style: TextStyle(fontSize: 16)),
                    ),
                  ),
                  const SizedBox(width: 16),
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: const Color(0xFFFFF59D),
                        foregroundColor: Colors.black,
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(30),
                          side: const BorderSide(color: Colors.black, width: 1.5),
                        ),
                        padding: const EdgeInsets.symmetric(vertical: 16),
                      ),
                      onPressed: () => Navigator.pop(context),
                      child: const Text('Back to Lessons', style: TextStyle(fontSize: 16)),
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

