                        child: DragTarget<String>(
                          builder: (context, candidateData, rejectedData) {
                            return Container(
                              width: 35,
                              height: 35,
                              decoration: BoxDecoration(
                                color: _dragTargets[index].isEmpty
                                    ? Colors.green[100]
                                    : Colors.white,
                                borderRadius: BorderRadius.circular(6),
