                              child: Center(
                                child: Text(
                                  _dragTargets[index],
                                  style: const TextStyle(
                                    fontSize: 12,
                                    fontWeight: FontWeight.bold,
                                  ),
                                ),
                              ),
                            );
                          },
                          onWillAccept: (data) {
                            return _dragTargets[index].isEmpty;
                          },
                          onAccept: (data) {
                            setState(() {
                              _dragTargets[index] = data;
                              _dragItems.remove(data);
                            });
