    final leftItems = question['leftItems'] as List;
    final rightItems = question['rightItems'] as List;
    
    return Container(
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: Colors.grey[50],
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: Colors.purple[200]!, width: 1.5),
      ),
      child: Column(
        children: [
          // Headers
          Row(
            children: [
              Expanded(
                child: Container(
                  padding: const EdgeInsets.all(6),
                  decoration: BoxDecoration(
                    color: Colors.purple[100],
                    borderRadius: BorderRadius.circular(6),
                  ),
                  child: const Text(
                    'Fraction',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 11),
                    textAlign: TextAlign.center,
                  ),
                ),
              ),
              const SizedBox(width: 8),
              Expanded(
                child: Container(
                  padding: const EdgeInsets.all(6),
                  decoration: BoxDecoration(
                    color: Colors.purple[100],
                    borderRadius: BorderRadius.circular(6),
                  ),
                  child: const Text(
                    'Description',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 11),
                    textAlign: TextAlign.center,
                  ),
                ),
              ),
            ],
          ),
          
          const SizedBox(height: 8),
          
          // Matching rows
          ...List.generate(leftItems.length, (index) {
            return Padding(
              padding: const EdgeInsets.only(bottom: 6),
              child: Row(
                children: [
                  // Left item
                  Expanded(
                    child: Container(
                      padding: const EdgeInsets.all(8),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.grey[300]!),
                      ),
                      child: Text(
                        leftItems[index] as String,
                        textAlign: TextAlign.center,
                        style: const TextStyle(fontSize: 11),
                      ),
                    ),
                  ),
                  
                  const SizedBox(width: 8),
                  
                  // Right dropdown
                  Expanded(
                    child: Container(
                      padding: const EdgeInsets.symmetric(horizontal: 6),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.purple[300]!),
                      ),
                      child: DropdownButton<int>(
                        value: _matchingSelections[_currentQuestion]?[index],
                        hint: const Text('Select', style: TextStyle(fontSize: 11)),
                        isExpanded: true,
                        underline: const SizedBox(),
                        iconSize: 18,
                        items: List.generate(rightItems.length, (i) {
                          return DropdownMenuItem<int>(
                            value: i,
                            child: Text(rightItems[i] as String, style: const TextStyle(fontSize: 11)),
                          );
                        }),
                        onChanged: _answeredQuestions[_currentQuestion] 
                            ? null 
                            : (value) {
                                _updateMatchingSelection(index, value!);
                              },
                      ),
                    ),
                  ),
                ],
              ),
            );
          }),
        ],
      ),
    );
  }

  // ===== DRAG AND DROP MATCH BUILDER =====
  Widget _buildDragDropMatch(Map<String, dynamic> question, double screenWidth) {
    final leftItems = question['leftItems'] as List;
    
    return StatefulBuilder(
      builder: (context, setState) {
        return Column(
          children: [
            // Left items with drop targets
            Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Colors.orange[50],
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.orange, width: 1.5),
              ),
              child: Column(
                children: List.generate(leftItems.length, (index) {
                  final filledValue = _matchFilledBlanks[_currentQuestion]?[index];
                  return Padding(
                    padding: const EdgeInsets.only(bottom: 8),
                    child: Row(
                      children: [
                        // Left item
                        Expanded(
                          flex: 2,
                          child: Container(
                            padding: const EdgeInsets.all(8),
                            decoration: BoxDecoration(
                              color: Colors.white,
                              borderRadius: BorderRadius.circular(6),
                              border: Border.all(color: Colors.orange[300]!),
                            ),
                            child: Text(
                              leftItems[index] as String,
                              textAlign: TextAlign.center,
                              style: const TextStyle(fontSize: 11),
                            ),
                          ),
                        ),
                        
                        const SizedBox(width: 8),
                        
                        // Drop target for match
                        Expanded(
                          child: DragTarget<String>(
                            builder: (context, candidateData, rejectedData) {
                              return Container(
                                height: 40,
                                decoration: BoxDecoration(
                                  color: filledValue == null
                                      ? Colors.orange[100]
                                      : Colors.white,
                                  borderRadius: BorderRadius.circular(6),
                                  border: Border.all(
                                    color: filledValue == null
                                        ? Colors.orange
                                        : Colors.orange[700]!,
                                    width: 1.5,
                                  ),
                                ),
                                child: Center(
                                  child: Text(
                                    filledValue ?? 'Drop',
                                    style: TextStyle(
                                      fontSize: 11,
                                      fontWeight: FontWeight.bold,
                                      color: filledValue == null ? Colors.grey : Colors.black,
                                    ),
                                  ),
                                ),
                              );
                            },
                            onWillAccept: (data) {
                              return _matchFilledBlanks[_currentQuestion]?[index] == null;
                            },
                            onAccept: (data) {
                              _updateMatchBlank(index, data);
                            },
                          ),
                        ),
                      ],
                    ),
                  );
                }),
              ),
            ),
            
            const SizedBox(height: 12),
            
            // Drag items
            Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Colors.red[50],
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.red, width: 1.5),
              ),
              child: Column(
                children: [
                  const Text(
                    'Drag answers:',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 11),
                  ),
                  const SizedBox(height: 8),
                  Wrap(
                    spacing: 6,
                    runSpacing: 6,
                    children: _dragItems.map((item) {
                      return Draggable<String>(
                        data: item,
                        feedback: Material(
                          child: Container(
                            padding: const EdgeInsets.all(8),
                            decoration: BoxDecoration(
                              color: Colors.red,
                              borderRadius: BorderRadius.circular(6),
                              boxShadow: [
                                BoxShadow(
                                  color: Colors.black.withOpacity(0.2),
                                  blurRadius: 3,
                                  offset: const Offset(0, 1),
                                ),
                              ],
                            ),
                            child: Text(
                              item,
                              style: const TextStyle(
                                color: Colors.white,
                                fontSize: 11,
                                fontWeight: FontWeight.bold,
                              ),
                            ),
                          ),
                        ),
                        childWhenDragging: Container(
                          padding: const EdgeInsets.all(8),
                          decoration: BoxDecoration(
                            color: Colors.grey[300],
                            borderRadius: BorderRadius.circular(6),
                          ),
                          child: Text(
                            item,
                            style: const TextStyle(
                              color: Colors.grey,
                              fontSize: 11,
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                        ),
                        child: Container(
                          padding: const EdgeInsets.all(8),
                          decoration: BoxDecoration(
                            color: Colors.white,
                            borderRadius: BorderRadius.circular(6),
                            border: Border.all(color: Colors.red, width: 1.5),
                          ),
                          child: Text(
                            item,
                            style: const TextStyle(
                              fontSize: 11,
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                        ),
                      );
                    }).toList(),
                  ),
                ],
              ),
            ),
          ],
        );
      },
    );
  }

  // ===== DRAG AND DROP SEQUENCE BUILDER =====
  Widget _buildDragDropSequence(Map<String, dynamic> question, double screenWidth) {
    final sequence = question['sequence'] as List;
    final blankPositions = question['blankPositions'] as List;
    
    return StatefulBuilder(
      builder: (context, setState) {
        return Column(
          children: [
            // Sequence with blanks
            Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Colors.teal[50],
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.teal, width: 1.5),
              ),
              child: Row(
                mainAxisAlignment: MainAxisAlignment.center,
                children: List.generate(sequence.length, (index) {
                  if (blankPositions.contains(index)) {
                    final filledValue = _sequenceFilledBlanks[_currentQuestion]?[index];
                    return Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 4),
                      child: DragTarget<String>(
                        builder: (context, candidateData, rejectedData) {
                          return Container(
                            width: 50,
                            height: 40,
                            decoration: BoxDecoration(
                              color: filledValue == null
                                  ? Colors.teal[100]
                                  : Colors.white,
                              borderRadius: BorderRadius.circular(6),
                              border: Border.all(
                                color: filledValue == null
                                    ? Colors.teal
                                    : Colors.teal[700]!,
                                width: 1.5,
                              ),
                            ),
                            child: Center(
                              child: Text(
                                filledValue ?? '?',
                                style: const TextStyle(
                                  fontSize: 13,
                                  fontWeight: FontWeight.bold,
                                ),
                              ),
                            ),
                          );
                        },
                        onWillAccept: (data) {
                          return _sequenceFilledBlanks[_currentQuestion]?[index] == null;
                        },
                        onAccept: (data) {
                          _updateSequenceBlank(index, data);
                        },
                      ),
                    );
                  } else {
                    return Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 4),
                      child: Container(
                        padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 8),
                        child: Text(
                          sequence[index] as String,
                          style: const TextStyle(
                            fontSize: 13,
                            fontWeight: FontWeight.bold,
                          ),
                        ),
                      ),
                    );
                  }
                }),
              ),
            ),
            
            const SizedBox(height: 12),
            
            // Drag items
            Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Colors.amber[50],
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.amber, width: 1.5),
              ),
              child: Column(
                children: [
                  const Text(
                    'Drag fractions:',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 11),
                  ),
                  const SizedBox(height: 8),
                  Wrap(
                    spacing: 6,
                    runSpacing: 6,
                    children: _dragItems.map((item) {
                      return Draggable<String>(
                        data: item,
                        feedback: Material(
                          child: Container(
                            padding: const EdgeInsets.all(8),
                            decoration: BoxDecoration(
                              color: Colors.amber,
                              borderRadius: BorderRadius.circular(6),
                              boxShadow: [
                                BoxShadow(
                                  color: Colors.black.withOpacity(0.2),
                                  blurRadius: 3,
                                  offset: const Offset(0, 1),
                                ),
                              ],
                            ),
                            child: Text(
                              item,
                              style: const TextStyle(
                                color: Colors.white,
                                fontSize: 13,
                                fontWeight: FontWeight.bold,
                              ),
                            ),
                          ),
                        ),
                        childWhenDragging: Container(
                          padding: const EdgeInsets.all(8),
                          decoration: BoxDecoration(
                            color: Colors.grey[300],
                            borderRadius: BorderRadius.circular(6),
                          ),
