                                      const SizedBox(width: 2),
                                      Text(
                                        'Done',
                                        style: TextStyle(
                                          fontSize: 9,
                                          color: Colors.green.shade700,
                                          fontWeight: FontWeight.bold,
                                        ),
                                      ),
                                    ],
                                  ),
                                ),
