                    ),

                    // Play/Lock button
                    Container(
                      width: 32,
                      height: 32,
                      decoration: BoxDecoration(
                        color: isCompleted ? Colors.green : (isUnlocked ? const Color(0xFFFFF59D) : Colors.grey.shade300),
                        shape: BoxShape.circle,
                        border: Border.all(
