                          _getCategoryName(currentQuestion['category']),
                          style: TextStyle(
                            fontSize: screenWidth * 0.035,
                            color: _getCategoryColor(currentQuestion['category']).withOpacity(0.8),
                          ),
                        ),
                      ],
