                          borderRadius: BorderRadius.circular(25),
                          side: const BorderSide(color: Colors.black, width: 1),
                        ),
                        padding: const EdgeInsets.symmetric(vertical: 12),
                        elevation: 1,
                      ),
                      onPressed: _currentQuestion > 0 ? _previousQuestion : null,
                      child: const Text('Previous', style: TextStyle(fontSize: 14)),
                    ),
                  ),
                  const SizedBox(width: 10),
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: const Color(0xFFFFF59D),
                        foregroundColor: Colors.black,
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(25),
                          side: const BorderSide(color: Colors.black, width: 1),
                        ),
                        padding: const EdgeInsets.symmetric(vertical: 12),
                        elevation: 1,
                      ),
                      onPressed: _answeredQuestions[_currentQuestion] ? _nextQuestion : null,
                      child: Text(
                        _currentQuestion == _questions.length - 1 ? 'Finish' : 'Next',
                        style: const TextStyle(fontSize: 14, fontWeight: FontWeight.bold),
                      ),
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }

  // ===== MULTIPLE CHOICE BUILDER =====
  Widget _buildMultipleChoice(Map<String, dynamic> question, double screenWidth) {
    return GridView.builder(
      shrinkWrap: true,
      physics: const NeverScrollableScrollPhysics(),
      gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 2,
        childAspectRatio: screenWidth > 600 ? 2.2 : 2.0,
        crossAxisSpacing: 8,
        mainAxisSpacing: 8,
      ),
      itemCount: (question['options'] as List).length,
      itemBuilder: (context, index) {
        final isAnswered = _answeredQuestions[_currentQuestion];
        final isSelected = _userAnswers[_currentQuestion] == index;
        final isCorrect = index == (question['correctAnswer'] as int);

        Color buttonColor = Colors.white;
        if (isAnswered) {
          if (isSelected && isCorrect) {
            buttonColor = Colors.green;
          } else if (isSelected && !isCorrect) {
            buttonColor = Colors.red;
          } else if (isCorrect) {
            buttonColor = Colors.green[100]!;
          }
        }

        return GestureDetector(
          onTap: isAnswered ? null : () => _answerQuestion(index),
          child: AnimatedContainer(
            duration: const Duration(milliseconds: 200),
            decoration: BoxDecoration(
              color: buttonColor,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(
                color: isSelected ? Colors.black : Colors.grey[300]!,
                width: isSelected ? 2 : 1,
              ),
              boxShadow: [
                if (!isAnswered)
                  BoxShadow(
                    color: Colors.black.withOpacity(0.05),
                    blurRadius: 2,
                    offset: const Offset(0, 1),
                  ),
              ],
            ),
            child: Center(
              child: Padding(
                padding: const EdgeInsets.all(6),
                child: Text(
                  (question['options'] as List)[index] as String,
                  textAlign: TextAlign.center,
                  style: TextStyle(
                    fontSize: screenWidth > 600 ? 18 : 16,
                    fontWeight: FontWeight.bold,
                  ),
                ),
              ),
            ),
          ),
        );
      },
    );
  }

  // ===== MATCHING TYPE BUILDER =====
  Widget _buildMatchingType(Map<String, dynamic> question, double screenWidth) {
    final leftItems = question['leftItems'] as List;
    final rightItems = question['rightItems'] as List;
    
    return Container(
      padding: const EdgeInsets.all(10),
      decoration: BoxDecoration(
        color: Colors.grey[50],
        borderRadius: BorderRadius.circular(10),
        border: Border.all(color: Colors.purple[200]!, width: 1.5),
      ),
      child: Column(
        children: [
          // Headers
          Row(
            children: [
              Expanded(
                child: Container(
                  padding: const EdgeInsets.all(6),
                  decoration: BoxDecoration(
                    color: Colors.purple[100],
                    borderRadius: BorderRadius.circular(6),
                  ),
                  child: const Text(
                    'Fraction/Description',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 11),
                    textAlign: TextAlign.center,
                  ),
                ),
              ),
              const SizedBox(width: 8),
              Expanded(
                child: Container(
                  padding: const EdgeInsets.all(6),
                  decoration: BoxDecoration(
                    color: Colors.purple[100],
                    borderRadius: BorderRadius.circular(6),
                  ),
                  child: const Text(
                    'Percentage',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 11),
                    textAlign: TextAlign.center,
                  ),
                ),
              ),
            ],
          ),
          
          const SizedBox(height: 8),
          
          // Matching rows
          ...List.generate(leftItems.length, (index) {
            return Padding(
              padding: const EdgeInsets.only(bottom: 6),
              child: Row(
                children: [
                  // Left item
                  Expanded(
                    child: Container(
                      padding: const EdgeInsets.all(8),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.grey[300]!),
                      ),
                      child: Text(
                        leftItems[index] as String,
                        textAlign: TextAlign.center,
                        style: const TextStyle(fontSize: 12),
                      ),
                    ),
                  ),
                  
                  const SizedBox(width: 8),
                  
                  // Right dropdown
                  Expanded(
                    child: Container(
                      padding: const EdgeInsets.symmetric(horizontal: 6),
                      decoration: BoxDecoration(
                        color: Colors.white,
                        borderRadius: BorderRadius.circular(6),
                        border: Border.all(color: Colors.purple[300]!),
                      ),
                      child: DropdownButton<int>(
                        value: _matchingSelections[_currentQuestion]?[index],
                        hint: const Text('Select', style: TextStyle(fontSize: 11)),
                        isExpanded: true,
                        underline: const SizedBox(),
                        iconSize: 18,
                        items: List.generate(rightItems.length, (i) {
                          return DropdownMenuItem<int>(
                            value: i,
                            child: Text(rightItems[i] as String, style: const TextStyle(fontSize: 11)),
                          );
                        }),
                        onChanged: _answeredQuestions[_currentQuestion] 
                            ? null 
                            : (value) {
                                _updateMatchingSelection(index, value!);
                              },
                      ),
                    ),
                  ),
                ],
              ),
            );
          }),
        ],
      ),
    );
  }

  // ===== DRAG AND DROP MATCH BUILDER =====
  Widget _buildDragDropMatch(Map<String, dynamic> question, double screenWidth) {
    final leftItems = question['leftItems'] as List;
    
    return StatefulBuilder(
      builder: (context, setState) {
        return Column(
          children: [
            // Left items with drop targets
            Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Colors.orange[50],
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.orange, width: 1.5),
              ),
              child: Column(
                children: List.generate(leftItems.length, (index) {
                  final filledValue = _matchFilledBlanks[_currentQuestion]?[index];
                  return Padding(
                    padding: const EdgeInsets.only(bottom: 8),
                    child: Row(
                      children: [
                        // Left item
                        Expanded(
                          flex: 2,
                          child: Container(
                            padding: const EdgeInsets.all(8),
                            decoration: BoxDecoration(
                              color: Colors.white,
                              borderRadius: BorderRadius.circular(6),
                              border: Border.all(color: Colors.orange[300]!),
                            ),
                            child: Text(
                              leftItems[index] as String,
                              textAlign: TextAlign.center,
                              style: const TextStyle(fontSize: 12),
                            ),
                          ),
                        ),
                        
                        const SizedBox(width: 8),
                        
                        // Drop target for match
                        Expanded(
                          child: DragTarget<String>(
                            builder: (context, candidateData, rejectedData) {
                              return Container(
                                height: 40,
                                decoration: BoxDecoration(
                                  color: filledValue == null
                                      ? Colors.orange[100]
                                      : Colors.white,
                                  borderRadius: BorderRadius.circular(6),
                                  border: Border.all(
                                    color: filledValue == null
                                        ? Colors.orange
                                        : Colors.orange[700]!,
                                    width: 1.5,
                                  ),
                                ),
                                child: Center(
                                  child: Text(
                                    filledValue ?? 'Drop',
                                    style: TextStyle(
                                      fontSize: 12,
                                      fontWeight: FontWeight.bold,
                                      color: filledValue == null ? Colors.grey : Colors.black,
                                    ),
                                  ),
                                ),
                              );
                            },
                            onWillAccept: (data) {
                              return _matchFilledBlanks[_currentQuestion]?[index] == null;
                            },
                            onAccept: (data) {
                              _updateMatchBlank(index, data);
                            },
                          ),
                        ),
                      ],
                    ),
                  );
                }),
              ),
            ),
            
            const SizedBox(height: 12),
            
            // Drag items
            Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: Colors.red[50],
                borderRadius: BorderRadius.circular(10),
                border: Border.all(color: Colors.red, width: 1.5),
              ),
              child: Column(
                children: [
                  const Text(
                    'Drag answers:',
                    style: TextStyle(fontWeight: FontWeight.bold, fontSize: 12),
                  ),
                  const SizedBox(height: 8),
                  Wrap(
                    spacing: 6,
                    runSpacing: 6,
                    children: _dragItems.map((item) {
                      return Draggable<String>(
                        data: item,
                        feedback: Material(
                          child: Container(
                            padding: const EdgeInsets.all(8),
                            decoration: BoxDecoration(
                              color: Colors.red,
                              borderRadius: BorderRadius.circular(6),
                              boxShadow: [
                                BoxShadow(
                                  color: Colors.black.withOpacity(0.2),
                                  blurRadius: 3,
                                  offset: const Offset(0, 1),
                                ),
                              ],
                            ),
                            child: Text(
                              item,
                              style: const TextStyle(
                                color: Colors.white,
                                fontSize: 12,
                                fontWeight: FontWeight.bold,
                              ),
                            ),
                          ),
                        ),
                        childWhenDragging: Container(
                          padding: const EdgeInsets.all(8),
                          decoration: BoxDecoration(
                            color: Colors.grey[300],
                            borderRadius: BorderRadius.circular(6),
                          ),
                          child: Text(
                            item,
                            style: const TextStyle(
                              color: Colors.grey,
                              fontSize: 12,
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                        ),
                        child: Container(
                          padding: const EdgeInsets.all(8),
                          decoration: BoxDecoration(
                            color: Colors.white,
                            borderRadius: BorderRadius.circular(6),
                            border: Border.all(color: Colors.red, width: 1.5),
                          ),
                          child: Text(
                            item,
                            style: const TextStyle(
                              fontSize: 12,
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                        ),
                      );
                    }).toList(),
                  ),
                ],
              ),
            ),
          ],
        );
      },
    );
  }

  Widget _buildResultsScreen() {
    final percentage = (_score / _questions.length * 100).round();
    final screenWidth = MediaQuery.of(context).size.width;

    String message;
    String emoji;
    Color color;

    if (percentage == 100) {
      message = 'Perfect Score!';
      emoji = '🏆';
      color = Colors.amber;
    } else if (percentage >= 80) {
      message = 'Great Job!';
      emoji = '🎉';
      color = Colors.green;
    } else if (percentage >= 60) {
      message = 'Good Try!';
      emoji = '👍';
      color = Colors.blue;
    } else {
      message = 'Keep Practicing!';
      emoji = '💪';
      color = Colors.orange;
    }

    return Scaffold(
      backgroundColor: Colors.white,
      appBar: AppBar(
        backgroundColor: Colors.white,
        leading: IconButton(
          icon: const Icon(Icons.arrow_back, color: Colors.black),
          onPressed: () => Navigator.pop(context),
        ),
        title: const Text('Exercise Complete'),
        centerTitle: true,
        elevation: 0,
      ),
      body: Center(
        child: Padding(
          padding: const EdgeInsets.all(20),
          child: Column(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              Text(
                emoji,
                style: const TextStyle(fontSize: 70),
              ),
              const SizedBox(height: 15),
              Text(
                message,
                style: TextStyle(
                  fontSize: screenWidth > 600 ? 30 : 26,
                  fontWeight: FontWeight.bold,
                  color: color,
                ),
              ),
              const SizedBox(height: 25),
              Container(
                padding: const EdgeInsets.all(20),
                decoration: BoxDecoration(
                  color: color.withOpacity(0.1),
                  borderRadius: BorderRadius.circular(15),
                  border: Border.all(color: color, width: 2),
                  boxShadow: [
                    BoxShadow(
                      color: color.withOpacity(0.2),
                      blurRadius: 10,
                      offset: const Offset(0, 4),
                    ),
                  ],
                ),
                child: Column(
                  children: [
                    const Text(
                      'Your Score',
                      style: TextStyle(fontSize: 16),
                    ),
                    const SizedBox(height: 8),
                    Text(
                      '$_score/${_questions.length}',
                      style: const TextStyle(fontSize: 40, fontWeight: FontWeight.bold),
                    ),
                    const SizedBox(height: 4),
                    Text(
                      '$percentage%',
                      style: const TextStyle(fontSize: 24),
                    ),
                  ],
                ),
              ),
              const SizedBox(height: 30),
              Row(
                children: [
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: Colors.white,
                        foregroundColor: Colors.black,
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(25),
                          side: const BorderSide(color: Colors.black, width: 1),
                        ),
                        padding: const EdgeInsets.symmetric(vertical: 14),
                      ),
                      onPressed: _restartExercise,
                      child: const Text('Try Again'),
                    ),
                  ),
                  const SizedBox(width: 10),
                  Expanded(
                    child: ElevatedButton(
                      style: ElevatedButton.styleFrom(
                        backgroundColor: const Color(0xFFFFF59D),
                        foregroundColor: Colors.black,
                        shape: RoundedRectangleBorder(
                          borderRadius: BorderRadius.circular(25),
                          side: const BorderSide(color: Colors.black, width: 1),
                        ),
                        padding: const EdgeInsets.symmetric(vertical: 14),
                      ),
                      onPressed: () => Navigator.pop(context),
                      child: const Text('Back to Lessons'),
                    ),
                  ),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

// ============ UPDATED ALGEBRA LESSONS SCREEN (4 subtopics only) ============
class AlgebraLessonsScreen extends StatefulWidget {
  const AlgebraLessonsScreen({super.key});

  @override
  State<AlgebraLessonsScreen> createState() => _AlgebraLessonsScreenState();
}

class _AlgebraLessonsScreenState extends State<AlgebraLessonsScreen> {
  // Track which lessons are expanded
  final Map<String, bool> _expandedLessons = {
    'algebra': false,
  };

  // Lesson data structure - UPDATED with only 4 subtopics (removed Mixed Operations)
  final List<Map<String, dynamic>> _lessons = [
    {
      'id': 'algebra',
      'title': 'Algebra',
      'description': 'Learn to find missing values in mathematical sentences',
      'color': const Color(0xFFD8A8FF), // Lavender color
      'icon': Icons.functions,
      'subtopics': [
        {
          'title': 'Missing Values in Addition',
          'learningObjectives': [
            'Find the missing value to complete addition sentences',
            'Example: 5 + ___ = 12',
            'Example: ___ + 8 = 15',
          ],
          'videoUrl': 'assets/Videos/AlgebAdd.mp4',
          'duration': '1:36',
        },
        {
          'title': 'Missing Values in Subtraction',
          'learningObjectives': [
            'Find the missing value to complete subtraction sentences',
            'Example: 15 - ___ = 7',
            'Example: ___ - 9 = 6',
          ],
          'videoUrl': 'assets/Videos/AlgebSub.mp4',
          'duration': '1:28',
        },
        {
          'title': 'Missing Values in Multiplication',
          'learningObjectives': [
            'Find the missing value to complete multiplication sentences',
            'Example: 6 × ___ = 42',
            'Example: ___ × 8 = 56',
          ],
          'videoUrl': 'assets/Videos/AlgebMulti.mp4',
          'duration': '1:27',
        },
        {
          'title': 'Missing Values in Division',
          'learningObjectives': [
            'Find the missing value to complete division sentences',
            'Example: 24 ÷ ___ = 6',
            'Example: ___ ÷ 5 = 9',
          ],
          'videoUrl': 'assets/Videos/AlgebDiv.mp4',
          'duration': '1:35',
        },
      ],
    },
  ];

  @override
  void initState() {
    super.initState();
    // Listen for unlock events
    progressManager.unlockStream.listen((topicName) {
      if (mounted && topicName == 'Algebra') {
        setState(() {});
      }
    });
    // Check if Algebra is unlocked
    _checkIfUnlocked();
  }

  void _checkIfUnlocked() {
    if (!progressManager.isTopicUnlocked('Algebra')) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            'Complete all lessons in Percentage first!',
            style: TextStyle(fontFamily: 'Poppins-Regular'),
          ),
          backgroundColor: Colors.orange,
          duration: const Duration(seconds: 2),
          behavior: SnackBarBehavior.floating,
        ),
      );
      Future.delayed(const Duration(seconds: 2), () {
        if (mounted) {
          Navigator.pop(context);
        }
      });
    }
  }

  // Check if lesson is unlocked (Algebra only has one lesson)
  bool _isLessonUnlocked(String lessonTitle) {
    return progressManager.isTopicUnlocked('Algebra');
  }

  // ============ IMPORTANT: Check if ALL videos in a lesson are completed ============
  bool _isLessonFullyCompleted(String lessonTitle) {
    try {
      final lesson = _lessons.firstWhere(
        (lesson) => lesson['title'] == lessonTitle,
      );
      final subtopics = lesson['subtopics'] as List;
      
      if (subtopics.isEmpty) return false;
      
      int completedCount = 0;
      for (var subtopic in subtopics) {
        if (progressManager.isSubtopicCompleted(lessonTitle, subtopic['title'])) {
          completedCount++;
        }
      }
      
      // Lesson is fully completed if ALL subtopics are completed
      return completedCount == subtopics.length;
    } catch (e) {
      return false;
    }
  }

  // Check if video is unlocked (sequential within lesson)
  bool _isVideoUnlocked(String lessonTitle, int videoIndex) {
    try {
      final lesson = _lessons.firstWhere(
        (lesson) => lesson['title'] == lessonTitle,
      );
      final subtopics = lesson['subtopics'] as List;
      
      if (videoIndex == 0) {
        return _isLessonUnlocked(lessonTitle);
      }
      
      final previousVideo = subtopics[videoIndex - 1];
      return progressManager.isSubtopicCompleted(lessonTitle, previousVideo['title']);
    } catch (e) {
      return false;
    }
  }

  // Get lesson progress
  double _getLessonProgress(String lessonTitle) {
    try {
      final lesson = _lessons.firstWhere(
        (lesson) => lesson['title'] == lessonTitle,
      );
      final subtopics = lesson['subtopics'] as List;
      
      if (subtopics.isEmpty) return 0;
      
      int completedCount = 0;
      for (var subtopic in subtopics) {
        if (progressManager.isSubtopicCompleted(lessonTitle, subtopic['title'])) {
          completedCount++;
        }
      }
      
      return completedCount / subtopics.length;
    } catch (e) {
      return 0;
    }
  }

  // Get completed count
  int _getCompletedCount(String lessonTitle) {
    try {
      final lesson = _lessons.firstWhere(
        (lesson) => lesson['title'] == lessonTitle,
      );
      final subtopics = lesson['subtopics'] as List;
      
      int completedCount = 0;
      for (var subtopic in subtopics) {
        if (progressManager.isSubtopicCompleted(lessonTitle, subtopic['title'])) {
          completedCount++;
        }
      }
      
      return completedCount;
    } catch (e) {
      return 0;
    }
  }

  void _toggleLesson(String lessonId) {
    setState(() {
      _expandedLessons[lessonId] = !(_expandedLessons[lessonId] ?? false);
    });
  }

  void _navigateToVideo(String lessonTitle, Map<String, dynamic> subtopic) {
    // Build learning objectives text
    String learningObjectives = subtopic['learningObjectives'].join('\n• ');
    
    Navigator.push(
      context,
      MaterialPageRoute(
        builder: (context) => AlgebraVideoScreen(
          lessonTitle: lessonTitle,
          videoTitle: subtopic['title'],
          videoUrl: subtopic['videoUrl'],
          learningObjective: 'Learning Objectives:\n• $learningObjectives',
        ),
      ),
    ).then((_) {
      setState(() {});
      
      // Check if Algebra topic is now fully completed
      _checkAlgebraCompletion();
    });
  }

  // Navigate to comprehensive exercise
  void _navigateToComprehensiveExercise() {
    Navigator.push(
      context,
      MaterialPageRoute(builder: (context) => AlgebraExerciseScreen(
        lessonName: 'Algebra',
        language: 'English',
        subLessonIndex: 0,
      )),
    ).then((_) {
      setState(() {});
    });
  }

  // Check if Algebra topic is fully completed
  void _checkAlgebraCompletion() {
    bool algebraCompleted = progressManager.isLessonCompleted('Algebra');
    
    if (algebraCompleted) {
      // Mark Algebra topic as completed
      progressManager.markTopicCompleted('Algebra');
      
      // All topics completed! Show congratulations message
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text(
            '🎉 Congratulations! You completed all topics! 🎉',
            style: TextStyle(fontFamily: 'Poppins-Regular', fontWeight: FontWeight.bold),
          ),
          backgroundColor: Colors.purple,
          duration: const Duration(seconds: 5),
          behavior: SnackBarBehavior.floating,
        ),
      );
    }
  }

