            Text(
              'Loading video...',
              style: TextStyle(color: Colors.white),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildErrorWidget() {
    return Container(
      color: Colors.black,
      child: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            const Icon(Icons.error_outline, color: Colors.red, size: 50),
            const SizedBox(height: 10),
            const Text(
              'Video not available',
              style: TextStyle(color: Colors.white, fontSize: 16),
            ),
            const SizedBox(height: 20),
            ElevatedButton(
              style: ElevatedButton.styleFrom(
                backgroundColor: const Color(0xFFFFF59D),
              ),
              onPressed: _initializeVideo,
              child: const Text('Try Again'),
            ),
          ],
        ),
      ),
    );
  }

  Widget _buildVideoControls() {
    return Container(
      color: Colors.black87,
      padding: const EdgeInsets.all(10),
      child: Column(
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              const Text('Speed:', style: TextStyle(color: Colors.white, fontSize: 12)),
              const SizedBox(width: 8),
              Container(
                padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                decoration: BoxDecoration(
                  color: Colors.white,
                  borderRadius: BorderRadius.circular(12),
                ),
                child: Text(
                  '${_playbackSpeed}x',
                  style: const TextStyle(fontSize: 12, fontWeight: FontWeight.bold),
                ),
              ),
              const SizedBox(width: 8),
              PopupMenuButton<double>(
                icon: const Icon(Icons.speed, size: 16, color: Colors.white),
                onSelected: _changePlaybackSpeed,
                itemBuilder: (context) => _speedOptions.map((speed) {
                  return PopupMenuItem<double>(
                    value: speed,
                    child: Text('${speed}x Speed', style: const TextStyle(fontSize: 12)),
                  );
                }).toList(),
              ),
            ],
          ),
          const SizedBox(height: 8),
          
          Row(
            mainAxisAlignment: MainAxisAlignment.center,
            children: [
              IconButton(
                icon: Icon(
                  _videoController.value.isPlaying ? Icons.pause : Icons.play_arrow,
                  color: Colors.white,
                ),
                onPressed: () {
                  setState(() {
                    if (_videoController.value.isPlaying) {
                      _videoController.pause();
                    } else {
                      _videoController.play();
                    }
                  });
                },
              ),
              
              IconButton(
                icon: const Icon(Icons.replay_10, color: Colors.white),
                onPressed: () {
                  final newPosition = _videoController.value.position - const Duration(seconds: 10);
                  _videoController.seekTo(newPosition);
                },
              ),
              
              Text(
                _formatDuration(_videoController.value.position),
                style: const TextStyle(color: Colors.white, fontSize: 12),
              ),
              
              Expanded(
                child: VideoProgressIndicator(
                  _videoController,
                  allowScrubbing: true,
                  colors: const VideoProgressColors(
                    playedColor: Colors.yellow,
                    bufferedColor: Colors.grey,
                    backgroundColor: Colors.white24,
                  ),
                ),
              ),
              
              Text(
                _formatDuration(_videoController.value.duration),
                style: const TextStyle(color: Colors.white, fontSize: 12),
              ),
              
              IconButton(
                icon: const Icon(Icons.forward_10, color: Colors.white),
                onPressed: () {
                  final newPosition = _videoController.value.position + const Duration(seconds: 10);
                  _videoController.seekTo(newPosition);
                },
              ),

              IconButton(
                icon: const Icon(Icons.replay, color: Colors.white),
                onPressed: () {
                  _videoController.seekTo(Duration.zero);
                  _videoController.play();
                },
              ),
            ],
          ),
        ],
      ),
    );
  }

  String _formatDuration(Duration duration) {
    String twoDigits(int n) => n.toString().padLeft(2, "0");
    String twoDigitMinutes = twoDigits(duration.inMinutes.remainder(60));
    String twoDigitSeconds = twoDigits(duration.inSeconds.remainder(60));
    return "${twoDigits(duration.inHours)}:$twoDigitMinutes:$twoDigitSeconds";
  }
}

// ============ UPDATED ALGEBRA EXERCISE SCREEN (15 items - Interactive) ============
class AlgebraExerciseScreen extends StatefulWidget {
  final String lessonName;
  final String language;
  final int subLessonIndex;

  const AlgebraExerciseScreen({
    super.key,
    required this.lessonName,
    required this.language,
    required this.subLessonIndex,
  });

  @override
  State<AlgebraExerciseScreen> createState() => _AlgebraExerciseScreenState();
}

class _AlgebraExerciseScreenState extends State<AlgebraExerciseScreen> {
  int _currentQuestion = 0;
  int _score = 0;
  bool _exerciseCompleted = false;
  List<dynamic> _userAnswers = List.filled(15, null);
  List<bool> _answeredQuestions = List.filled(15, false);
  
  // For drag and drop
  List<String> _dragItems = [];
  List<String> _dragTargets = [];
  
  // For matching type
  Map<int, Map<int, int>> _matchingSelections = {};
  
  // For drag drop match
  Map<int, Map<int, String>> _matchFilledBlanks = {};
  
  // For drag drop sequence
  Map<int, Map<int, String>> _sequenceFilledBlanks = {};
  
  // Track if drag items are initialized
  bool _dragItemsInitialized = false;

  final List<Map<String, dynamic>> _questions = [
    // ===== ADDITION - MISSING VALUE (4 items) =====
